// Group stale leads by assignee. Each output item = one message
// going to one assignee with all THEIR stale leads listed inline.
// This collapses what used to be N per-lead messages into M messages
// where M = unique assignees (typically 2-4 instead of 10-20).
const rows = $input.first().json;
const leads = Array.isArray(rows) ? rows : (rows.data ?? []);
if (!leads.length) {
  return [];
}

const byAssignee = new Map();
for (const l of leads) {
  const key = l.assigned_employee_phone || '(no-phone)';
  if (!byAssignee.has(key)) {
    byAssignee.set(key, {
      assignee_phone: l.assigned_employee_phone || '',
      assignee_name: l.assigned_employee_name || 'Unknown',
      leads: [],
    });
  }
  byAssignee.get(key).leads.push(l);
}

const MAX_INLINE = 8;
const out = [];
for (const g of byAssignee.values()) {
  if (!g.assignee_phone) continue; // skip leads without assigned phone
  const total = g.leads.length;
  const inline = g.leads.slice(0, MAX_INLINE).map(l => {
    const hrs = Math.floor(Number(l.hours_since_update) || 0);
    const name = (l.customer_name || 'Unknown').slice(0, 30);
    return `${name} (${l.status}, ${hrs}h)`;
  }).join(' · ');
  const more = total > MAX_INLINE ? ` · +${total - MAX_INLINE} more` : '';
  const title = `⏰ *Stale leads >24h* — ${total} lead${total === 1 ? '' : 's'} assigned to ${g.assignee_name}`;
  const body = `${inline}${more} · Open ERP to advance: call, requalify, or mark lost.`;
  out.push({
    json: {
      to_phone: g.assignee_phone,
      title,
      body,
      lead_count: total,
    },
  });
}
return out;
